declare module '*&format=webp' {
  const src: string;
  export default src;
}

declare module '*&format=avif' {
  const src: string;
  export default src;
}

declare module '*&format=avif&width=*' {
  const src: string;
  export default src;
}

declare module '*&format=webp&width=*' {
  const src: string;
  export default src;
}
